mysql_example.dsl_configuration:
{
  "connector_metadata": {
    "connector_name": "jdbc_mysql",
    "connector_label": "MySQL",
    "connector_description": "JDBC connector for MySQL databases"
  },
  "jdbc_driver": {
    "driver_class_name": "com.mysql.cj.jdbc.Driver"
  },
  "connection_properties": {
    "additional_properties": [
      {
        "name": "ssl",
        "label": "Use SSL",
        "description": "Enable SSL/TLS encrypted connection",
        "type": "boolean",
        "required": false,
        "default_value": "false"
      },
      {
        "name": "server_timezone",
        "label": "Server Timezone",
        "description": "Server timezone (e.g., UTC, America/New_York)",
        "type": "string",
        "required": false,
        "default_value": "UTC"
      }
    ]
  },
  "authentication": {
    "methods": [
      {
        "type": "basic",
        "enabled": true
      }
    ]
  },
  "database_specific_features": {
    "supports_schemas": false,
    "supports_catalogs": true,
    "default_schema": null,
    "system_schemas": ["information_schema", "mysql", "performance_schema", "sys"],
    "identifier_quote_char": "`"
  },
  "url_template": {
    "template": "jdbc:mysql://{host}:{port}/{database}"
  },
  "validation_rules": {
    "rules": [
      {
        "property": "port",
        "rule": "range",
        "min": 1,
        "max": 65535
      }
    ]
  }
}

postgresql_example.dsl_configuration:
{
  "connector_metadata": {
    "connector_name": "jdbc_postgres",
    "connector_label": "PostgreSQL",
    "connector_description": "JDBC connector for PostgreSQL databases"
  },
  "jdbc_driver": {
    "driver_class_name": "org.postgresql.Driver"
  },
  "connection_properties": {
    "additional_properties": [
      {
        "name": "ssl",
        "label": "Use SSL",
        "description": "Enable SSL/TLS encrypted connection",
        "type": "boolean",
        "required": false,
        "default_value": "false"
      },
      {
        "name": "ssl_mode",
        "label": "SSL Mode",
        "description": "SSL mode (disable, allow, prefer, require, verify-ca, verify-full)",
        "type": "string",
        "required": false,
        "default_value": "prefer"
      }
    ]
  },
  "authentication": {
    "methods": [
      {
        "type": "basic",
        "enabled": true
      }
    ]
  },
  "database_specific_features": {
    "supports_schemas": true,
    "supports_catalogs": false,
    "default_schema": "public",
    "system_schemas": ["information_schema", "pg_catalog", "pg_toast"],
    "identifier_quote_char": "\""
  },
  "url_template": {
    "template": "jdbc:postgresql://{host}:{port}/{database}"
  },
  "validation_rules": {
    "rules": [
      {
        "property": "port",
        "rule": "range",
        "min": 1,
        "max": 65535
      }
    ]
  }
}

oracle_example.dsl_configuration:
{
  "connector_metadata": {
    "connector_name": "jdbc_oracle",
    "connector_label": "Oracle Database",
    "connector_description": "JDBC connector for Oracle databases"
  },
  "jdbc_driver": {
    "driver_class_name": "oracle.jdbc.OracleDriver"
  },
  "connection_properties": {
    "additional_properties": [
      {
        "name": "service_name",
        "label": "Service Name",
        "description": "Oracle service name (alternative to SID)",
        "type": "string",
        "required": false
      },
      {
        "name": "connection_type",
        "label": "Connection Type",
        "description": "Connection type: SID or SERVICE_NAME",
        "type": "string",
        "required": false,
        "default_value": "SID"
      }
    ]
  },
  "authentication": {
    "methods": [
      {
        "type": "basic",
        "enabled": true
      }
    ]
  },
  "database_specific_features": {
    "supports_schemas": true,
    "supports_catalogs": false,
    "default_schema": null,
    "system_schemas": ["SYS", "SYSTEM", "SYSAUX", "CTXSYS", "MDSYS", "OLAPSYS"],
    "identifier_quote_char": "\""
  },
  "url_template": {
    "template": "jdbc:oracle:thin:@{host}:{port}:{database}"
  },
  "validation_rules": {
    "rules": [
      {
        "property": "port",
        "rule": "range",
        "min": 1,
        "max": 65535
      }
    ]
  }
}

sqlserver_example.dsl_configuration:
{
  "connector_metadata": {
    "connector_name": "jdbc_sqlserver",
    "connector_label": "SQL Server",
    "connector_description": "JDBC connector for Microsoft SQL Server databases"
  },
  "jdbc_driver": {
    "driver_class_name": "com.microsoft.sqlserver.jdbc.SQLServerDriver"
  },
  "connection_properties": {
    "additional_properties": [
      {
        "name": "encrypt",
        "label": "Encrypt Connection",
        "description": "Enable connection encryption",
        "type": "boolean",
        "required": false,
        "default_value": "false"
      },
      {
        "name": "trust_server_certificate",
        "label": "Trust Server Certificate",
        "description": "Trust server certificate without validation",
        "type": "boolean",
        "required": false,
        "default_value": "false"
      },
      {
        "name": "instance_name",
        "label": "Instance Name",
        "description": "SQL Server instance name",
        "type": "string",
        "required": false
      }
    ]
  },
  "authentication": {
    "methods": [
      {
        "type": "basic",
        "enabled": true
      }
    ]
  },
  "database_specific_features": {
    "supports_schemas": true,
    "supports_catalogs": true,
    "default_schema": "dbo",
    "system_schemas": ["sys", "INFORMATION_SCHEMA"],
    "identifier_quote_char": "\""
  },
  "url_template": {
    "template": "jdbc:sqlserver://{host}:{port};databaseName={database}"
  },
  "validation_rules": {
    "rules": [
      {
        "property": "port",
        "rule": "range",
        "min": 1,
        "max": 65535
      }
    ]
  }
}

